import java.util.*;
import java.io.*;

public class Main {
    static long[] solveCase(long[] a, long[] b) {
        // your code here — return one array with all numbers of a and b in sorted order
        return new long[0];
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StreamTokenizer in = new StreamTokenizer(br);
        in.nextToken();
        int t = (int) in.nval;
        StringBuilder out = new StringBuilder();
        while (t-- > 0) {
            in.nextToken();
            int n = (int) in.nval;
            in.nextToken();
            int m = (int) in.nval;
            long[] a = new long[n];
            for (int i = 0; i < n; i++) { in.nextToken(); a[i] = (long) in.nval; }
            long[] b = new long[m];
            for (int i = 0; i < m; i++) { in.nextToken(); b[i] = (long) in.nval; }
            long[] merged = solveCase(a, b);
            for (int i = 0; i < merged.length; i++) {
                if (i > 0) out.append(' ');
                out.append(merged[i]);
            }
            out.append('\n');
        }
        System.out.print(out);
    }
}

